import { ZuploContext, ZuploRequest } from "@zuplo/runtime";

export default async function (
  request: ZuploRequest,
  context: ZuploContext,
) {
  const url = "http://127.0.0.1:8080/api/data";
  const maxRetries = 3;
  let lastResponse: Response;

  for (let i = 0; i <= maxRetries; i++) {
    try {
      // Forward the request to the upstream service
      // We use a new Request object or just fetch the URL with headers
      // Since it's a GET request, we don't need to worry about the body
      lastResponse = await fetch(url, {
        method: request.method,
        headers: request.headers,
      });

      if (lastResponse.status !== 503) {
        return lastResponse;
      }

      context.log.info(`Attempt ${i + 1} returned 503. ${i < maxRetries ? "Retrying..." : "Max retries reached."}`);
    } catch (err) {
      context.log.error(`Error during fetch attempt ${i + 1}: ${err.message}`);
      // If it's a network error, we might want to retry as well, 
      // but the requirement specifically mentions 503.
      // However, usually retries handle transient errors.
      // I'll stick to the 503 requirement.
      throw err;
    }
  }

  return lastResponse;
}

